product-service: build: context: ./backend/product-service dockerfile: Dockerfile container_name: scn-product restart: unless-stopped depends_on: - config-service - mongodb environment: CONFIG_SERVER_URL: http://config-service:8888 EUREKA_ENABLED: "true" EUREKA_DEFAULT_ZONE: http://discovery-service:8761/eureka PRODUCT_MONGO_URI: mongodb://mongodb:27017/supercenter_product_db SPRING_MONGODB_URI: mongodb://mongodb:27017/supercenter_product_db JWT_SECRET: ${JWT_SECRET}
map-service: build: context: ./backend/map-service dockerfile: Dockerfile container_name: scn-map restart: unless-stopped depends_on: - config-service - mongodb environment: CONFIG_SERVER_URL: http://config-service:8888 EUREKA_ENABLED: "true" EUREKA_DEFAULT_ZONE: http://discovery-service:8761/eureka MAP_MONGO_URI: mongodb://mongodb:27017/supercenter_map_db SPRING_MONGODB_URI: mongodb://mongodb:27017/supercenter_map_db JWT_SECRET: ${JWT_SECRET}
user-service: build: context: ./backend/user-service dockerfile: Dockerfile container_name: scn-user restart: unless-stopped depends_on: - config-service - mysql environment: CONFIG_SERVER_URL: http://config-service:8888 EUREKA_ENABLED: "true" EUREKA_DEFAULT_ZONE: http://discovery-service:8761/eureka USER_DB_URL: jdbc:mysql://mysql:3306/user_db?createDatabaseIfNotExist=true&useSSL=false&allowPublicKeyRetrieval=true&serverTimezone=UTC USER_DB_USERNAME: root USER_DB_PASSWORD: ${MYSQL_ROOT_PASSWORD} JWT_SECRET: ${JWT_SECRET}
gateway-service: build: context: ./backend/gateway-service dockerfile: Dockerfile container_name: scn-gateway restart: unless-stopped depends_on: - config-service - auth-service - product-service - map-service - user-service environment: CONFIG_SERVER_URL: http://config-service:8888 EUREKA_ENABLED: "true" EUREKA_DEFAULT_ZONE: http://discovery-service:8761/eureka ports: - "${GATEWAY_HOST_PORT:-8088}:8080"
frontend: build: context: ./frontend/store-navigation-frontend dockerfile: Dockerfile container_name: scn-frontend restart: unless-stopped depends_on: - gateway-service ports: - "${FRONTEND_HOST_PORT:-5174}:80"
volumes: mysql_data: mongo_data:

server {
  listen 80;
  server_name _;

  root /usr/share/nginx/html;
  index index.html;

  location / {
    try_files $uri $uri/ /index.html;
  }

  location /api/ {
    proxy_pass http://gateway-service:8080/api/;
    proxy_http_version 1.1;
    proxy_set_header Host $host;
    proxy_set_header X-Real-IP $remote_addr;
    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    proxy_set_header X-Forwarded-Proto $scheme;
  }
}

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// https://vite.dev/config/
export default defineConfig({
  plugins: [react()],
  server: {
    proxy: {
      '/api/v1/auth': {
        target: 'http://localhost:8081',
        changeOrigin: true,
      },
      '/api/v1/products': {
        target: 'http://localhost:8082',
        changeOrigin: true,
      },
      '/api/v1/categories': {
        target: 'http://localhost:8082',
        changeOrigin: true,
      },
      '/api/v1/locations': {
        target: 'http://localhost:8083',
        changeOrigin: true,
      },
      '/api/v1/users': {
        target: 'http://localhost:8084',
        changeOrigin: true,
      },
    },
  },
})

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

const devApiTarget = process.env.VITE_DEV_API_TARGET || 'http://localhost:8088'

// https://vite.dev/config/
export default defineConfig({
  plugins: [react()],
  server: {
    proxy: {
      '/api': {
        target: devApiTarget,
        changeOrigin: true,
      },
    },
  },
})
